#include <iostream>
#include <string>
#include <iomanip>
// Assuming BankAccount class is defined in the context (from the .cpp file)

int main() {
    std::string command;
    double amount;
    BankAccount* account = nullptr;

    while (std::cin >> command) {
        if (command == "init") {
            std::cin >> amount;
            if (account) {
                delete account;
            }
            account = new BankAccount(amount);
            std::cout << "Account initialized with balance: " << std::fixed << std::setprecision(2) << account->getBalance() << std::endl;
        } else if (command == "deposit") {
            std::cin >> amount;
            if (account) {
                account->deposit(amount);
            } else {
                std::cout << "Error: Account not initialized." << std::endl;
            }
        } else if (command == "withdraw") {
            std::cin >> amount;
            if (account) {
                account->withdraw(amount);
            } else {
                std::cout << "Error: Account not initialized." << std::endl;
            }
        } else if (command == "get_balance") {
            if (account) {
                std::cout << "Current balance: " << std::fixed << std::setprecision(2) << account->getBalance() << std::endl;
            } else {
                std::cout << "Error: Account not initialized." << std::endl;
            }
        } else {
            std::cout << "Unknown command: " << command << std::endl;
        }
    }

    if (account) {
        delete account;
    }
    return 0;
}
